#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool isBipartite(vector<vector<int>>& graph) {
        vector<int> color(graph.size(), -1);
        for (int i = 0; i < graph.size(); i++) {
            if (color[i] == -1) {
                if (!dfs(graph, color, i, 0)) return false;
            }
        }
        return true;
    }
private:
    bool dfs(vector<vector<int>>& graph, vector<int>& color, int node, int c) {
        if (color[node] != -1) return color[node] == c;
        color[node] = c;
        for (int neighbor : graph[node]) {
            if (!dfs(graph, color, neighbor, 1 - c)) return false;
        }
        return true;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, m;
    cin >> n >> m;
    vector<vector<int>> graph(n);
    for (int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        graph[u - 1].push_back(v - 1);
        graph[v - 1].push_back(u - 1);
    }
    Solution sol;
    bool ans = sol.isBipartite(graph);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
